from web3 import Web3
import json

class WalletAuth:
    def __init__(self, private_key):
        self.private_key = private_key
        self.w3 = Web3(Web3.HTTPProvider('https://mainnet.infura.io/v3/YOUR_PROJECT_ID'))

    def verify_signature(self, signed_message):
        try:
            address = self.w3.eth.account.recover(signed_message['signature'], message=signed_message['message'])
            if address == self.w3.toChecksumAddress(self.private_key):
                return True
            else:
                return False
        except Exception as e:
            print(f"Error verifying signature: {str(e)}")
            return None

    def authenticate(self, signed_message):
        verified = self.verify_signature(signed_message)
        if verified is not None and verified:
            return True
        else:
            return False


